a=json.load(open('parsed_ALL.json',encoding='utf-8'))
def tag(q):
    text=q['q']+' '+' '.join(q['o'])
    for kw,topic in RULES.get(q['subject'],[]):
        if kw in text:
            return topic
    return ''
cov=defaultdict(lambda:[0,0])
for q in a:
    q['topic']=tag(q)
    cov[q['subject']][1]+=1
    if q['topic']: cov[q['subject']][0]+=1
json.dump(a,open('tagged_ALL.json','w',encoding='utf-8'),ensure_ascii=False,indent=1)
lines=[]
for s in ['biochem','mol','cell','physio']:
    got,tot=cov[s]; lines.append(f"{s}: tagged {got}/{tot} ({100*got//max(tot,1)}%)")
total_t=sum(1 for q in a if q['topic'])
lines.append(f"TOTAL tagged {total_t}/{len(a)}")
open('tag_report.txt','w',encoding='utf-8').write('\n'.join(lines))
print('\n'.join(lines))
